insert into projects (tag, title, description, img, area, storeys, status, sort_order) values ('Residential', '4-Storey Family Home — Kathmandu', 'Earthquake-resistant RCC structure with modern facade. Full design, approval, and supervised construction.', 'https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800&q=80', '2,400 sq.ft', '3 Storeys', 'Completed', 1);
insert into projects (tag, title, description, img, area, storeys, status, sort_order) values ('Design + Build', 'Modern Residence — Lalitpur', 'Contemporary 2-storey home with open-plan living spaces and structural design per NBC standards.', 'https://images.unsplash.com/photo-1580587771525-78b9dba3b914?w=800&q=80', '1,800 sq.ft', '2 Storeys', 'Completed', 2);
insert into projects (tag, title, description, img, area, storeys, status, sort_order) values ('Structural Design', 'Family Residence — Bhaktapur', 'Full structural analysis and NBC-compliant drawings for a 4-storey family residence. Municipality approved.', 'https://images.unsplash.com/photo-1592595896616-c37162298647?w=800&q=80', '3,100 sq.ft', '4 Storeys', 'Completed', 3);
insert into projects (tag, title, description, img, area, storeys, status, sort_order) values ('Commercial', 'Mixed-Use Building — Pokhara', 'Ground-floor commercial units with residential floors above. Structural design, supervision, and handover.', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '4,200 sq.ft', '5 Storeys', 'Completed', 4);
insert into projects (tag, title, description, img, area, storeys, status, sort_order) values ('Renovation', 'Structural Reinforcement — Biratnagar', 'Full structural assessment and reinforcement of an existing 2-storey home. Seismic retrofitting completed.', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', '1,600 sq.ft', '2 Storeys', 'Completed', 5);
insert into projects (tag, title, description, img, area, storeys, status, sort_order) values ('Interior Design', 'Luxury Interior — Chitwan', 'Complete interior design, space planning, and premium finishing for a newly constructed residence.', 'https://images.unsplash.com/photo-1484154218962-a197022b5858?w=800&q=80', '2,200 sq.ft', '2 Storeys', 'Completed', 6);
insert into testimonials (project_type, text, name, location, sort_order) values ('3-Storey Residence · Kathmandu', 'हामीले घर बनाउनेभन्दा पहिले धेरै कम्पनीसँग भेट्यौँ। सबैले राम्रो मात्र भन्नुभयो। Afno Ghar ले भने हाम्रो बजेटभित्र के सम्भव छ र के सम्भव छैन भनेर खुलेर भन्नुभयो। त्यही इमानदारीले हामीलाई विश्वास दिलायो। निर्माणको क्रममा साना–ठूला समस्या आए पनि लुकाउनुभएन, समाधानसहित जानकारी दिनुभयो। अहिले घर बनेर परिवारसँग बस्दा एउटा सन्तुष्टि छ—हामीले सही निर्णय गरेका रहेछौँ।', 'Ram Kumar Shrestha', 'Kathmandu', 1);
insert into testimonials (project_type, text, name, location, sort_order) values ('Design + Build · Lalitpur', 'Very professional team. They explained everything clearly, completed on time, and the construction quality is excellent. Our house passed inspection on the first attempt — no issues at all.', 'Sita Maharjan', 'Lalitpur', 2);
insert into testimonials (project_type, text, name, location, sort_order) values ('3 Story Building Design And Build | Bhaktapur', 'घर बनाउने निर्णय हाम्रो जीवनकै सबैभन्दा ठूलो निर्णय थियो। सुरुमा धेरै डर थियो—बजेट बढ्ने हो कि, काम बिग्रिने हो कि, गुणस्तर कस्तो हुने हो भनेर। तर Afno Ghar ले सुरुदेखि अन्तिम चाबी हस्तान्तरणसम्म प्रत्येक चरणमा हामीलाई स्पष्ट जानकारी दियो। अहिले घरमा बस्दा साँच्चै सही टोली रोजेछौँ भन्ने महसुस हुन्छ। धन्यवाद सम्पूर्ण टिमलाई।', 'Bikram Poudel', 'Bhaktapur', 3);
insert into testimonials (project_type, text, name, location, sort_order) values ('2 And Half Story Building · Lalitpur ', 'From design to handover, everything was handled with great care. The engineer assigned to us was always available. The result exceeded what we had imagined.', 'Anita Karki', 'Lalitpur ', 4);
insert into testimonials (project_type, text, name, location, sort_order) values ('Commercial Building · Biratnagar', 'We hired Afno Ghar for our commercial project and they delivered outstanding results. Attention to detail, commitment to deadlines, and honest cost estimates throughout.', 'Nabin Rai', 'Biratnagar', 5);
insert into testimonials (project_type, text, name, location, sort_order) values ('Interior Design · Chitwan', 'The interior design team understood our vision perfectly. They transformed our house into a home we are truly proud of — on budget and without any compromise on quality.', 'Priya Shrestha', 'Chitwan', 6);
